use crate::decoders::{Crack, CrackResult, Decoder, check_string_success};use crate::checkers::CheckerTypes;use std::marker::PhantomData;pub struct RailfenceDecoder;fn railfence_decode(text: &str, rails: usize) -> String {    let len = text.len();    if rails <= 1 || rails >= len {        return text.to_string();    }    let mut fence: Vec<Vec<Option<char>>> = vec![vec![None; len]; rails];    let mut row = 0isize;    let mut dir = 1isize;    for col in 0..len {        fence[row as usize][col] = Some('_');        if row == (rails as isize - 1) {            dir = -1;        } else if row == 0 {            dir = 1;        }        row += dir;    }    let mut idx = 0;    for r in 0..rails {        for c in 0..len {            if fence[r][c].is_some() {                fence[r][c] = Some(text.chars().nth(idx).unwrap());                idx += 1;            }        }    }    let mut result = String::with_capacity(len);    row = 0isize;    dir = 1isize;    for col in 0..len {        if let Some(ch) = fence[row as usize][col] {            result.push(ch);        }        if row == (rails as isize - 1) {            dir = -1;        } else if row == 0 {            dir = 1;        }        row += dir;    }    result}impl Crack for Decoder<RailfenceDecoder> {    fn crack(&self, text: &str, checker: &CheckerTypes) -> CrackResult {        let mut result = CrackResult::new(self.get_name(), self.get_description(), self.get_link());        result.encrypted_text = text.to_string();        for rails in 2..=10 {            let decoded = railfence_decode(text, rails);            if check_string_success(&decoded, text) {                let check_result = checker.check_text(&decoded);                if check_result.is_identified {                    result.success = true;                    result.unencrypted_text = Some(vec![decoded]);                    result.key = Some(rails.to_string());                    result.checker_name = check_result.checker_name;                    return result;                }            }        }        result    }    fn get_name(&self) -> &'static str { "Railfence" }    fn get_popularity(&self) -> f32 { 0.4 }    fn get_tags(&self) -> &'static [&'static str] { &["railfence", "decoder", "cipher", "classical"] }    fn get_description(&self) -> &'static str { "Railfence cipher writes plaintext diagonally across multiple rows (rails) and reads off row by row." }    fn get_link(&self) -> &'static str { "https://en.wikipedia.org/wiki/Rail_fence_cipher" }}impl Decoder<RailfenceDecoder> {    pub fn new() -> Self {        Decoder {            name: "Railfence",            description: "Railfence cipher writes plaintext diagonally across multiple rows.",            link: "https://en.wikipedia.org/wiki/Rail_fence_cipher",            tags: vec!["railfence", "decoder", "cipher", "classical"],            popularity: 0.4,            phantom: PhantomData,        }    }}



